@namespace sv_cdb4f7d1ce044e3994a66919fac7e653.Components.Pages.Settings

<nav class="settings-sidebar">
    <h5 class="px-3 py-2 text-muted text-uppercase small fw-bold">Settings</h5>
    <ul class="nav flex-column">
        @foreach (var section in Sections)
        {
            <li class="nav-item">
                <button class="nav-link settings-nav-link @(section == ActiveSection ? "active" : "")"
                        @onclick="() => OnSectionChanged.InvokeAsync(section)">
                    <span class="me-2">@GetIcon(section)</span>
                    @section
                </button>
            </li>
        }
    </ul>
</nav>

@code {
    [Parameter, EditorRequired] public string ActiveSection { get; set; } = "";
    [Parameter, EditorRequired] public EventCallback<string> OnSectionChanged { get; set; }

    private static readonly string[] Sections = ["Profile", "Notifications", "Security", "Appearance"];

    private static string GetIcon(string section) => section switch
    {
        "Profile" => "👤",
        "Notifications" => "🔔",
        "Security" => "🔒",
        "Appearance" => "🎨",
        _ => "⚙️"
    };
}

.settings-sidebar {
    min-width: 220px;
    border-right: 1px solid #dee2e6;
    padding: 1rem 0;
    background-color: #f8f9fa;
    height: 100%;
}

.settings-nav-link {
    display: flex;
    align-items: center;
    width: 100%;
    padding: 0.6rem 1.25rem;
    border: none;
    background: none;
    text-align: left;
    color: #495057;
    font-size: 0.95rem;
    cursor: pointer;
    border-left: 3px solid transparent;
    transition: all 0.15s ease;
}

.settings-nav-link:hover {
    background-color: #e9ecef;
    color: #212529;
}

.settings-nav-link.active {
    background-color: #e7f1ff;
    color: #0d6efd;
    border-left-color: #0d6efd;
    font-weight: 600;
}

@namespace sv_cdb4f7d1ce044e3994a66919fac7e653.Components.Pages.Settings
@using sv_cdb4f7d1ce044e3994a66919fac7e653.Models

<div class="change-password-panel">
    <button class="btn btn-outline-secondary mb-3" @onclick="ToggleExpanded">
        @(IsExpanded ? "▾" : "▸") Change Password
    </button>

    @if (IsExpanded)
    {
        <div class="card card-body">
            @if (!string.IsNullOrEmpty(_errorMessage))
            {
                <div class="alert alert-danger py-2">@_errorMessage</div>
            }
            @if (_successMessage)
            {
                <div class="alert alert-success py-2">Password updated successfully!</div>
            }

            <div class="mb-3">
                <label class="form-label">Current Password</label>
                <input type="password" class="form-control" @bind="_currentPassword" />
            </div>
            <div class="mb-3">
                <label class="form-label">New Password</label>
                <input type="password" class="form-control" @bind="_newPassword" />
            </div>
            <div class="mb-3">
                <label class="form-label">Confirm New Password</label>
                <input type="password" class="form-control" @bind="_confirmPassword" />
            </div>
            <button class="btn btn-primary" @onclick="UpdatePassword" disabled="@_saving">
                @(_saving ? "Updating…" : "Update Password")
            </button>
        </div>
    }
</div>

@code {
    [Parameter, EditorRequired] public EventCallback<(string Current, string New)> OnPasswordChange { get; set; }

    private bool IsExpanded;
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private string? _errorMessage;
    private bool _successMessage;
    private bool _saving;

    private void ToggleExpanded() => IsExpanded = !IsExpanded;

    private async Task UpdatePassword()
    {
        _errorMessage = null;
        _successMessage = false;

        if (string.IsNullOrWhiteSpace(_currentPassword))
        {
            _errorMessage = "Current password is required.";
            return;
        }
        if (_newPassword.Length < 6)
        {
            _errorMessage = "New password must be at least 6 characters.";
            return;
        }
        if (_newPassword != _confirmPassword)
        {
            _errorMessage = "Passwords do not match.";
            return;
        }

        _saving = true;
        await OnPasswordChange.InvokeAsync((_currentPassword, _newPassword));
        _saving = false;
        _successMessage = true;
        _currentPassword = "";
        _newPassword = "";
        _confirmPassword = "";
    }
}

@namespace sv_cdb4f7d1ce044e3994a66919fac7e653.Components.Pages.Settings
@using sv_cdb4f7d1ce044e3994a66919fac7e653.Models

<div class="table-responsive">
    <table class="table table-hover align-middle">
        <thead class="table-light">
            <tr>
                <th>Device</th>
                <th>Location</th>
                <th>Last Active</th>
                <th></th>
            </tr>
        </thead>
        <tbody>
            @foreach (var session in Sessions)
            {
                <tr>
                    <td>@session.Device</td>
                    <td>@session.Location</td>
                    <td>@FormatLastActive(session.LastActive)</td>
                    <td>
                        @if (session.Id == CurrentSessionId)
                        {
                            <span class="badge bg-success">Current</span>
                        }
                        else
                        {
                            <button class="btn btn-outline-danger btn-sm"
                                    @onclick="() => RequestRevoke(session)">
                                Revoke
                            </button>
                        }
                    </td>
                </tr>
            }
        </tbody>
    </table>
</div>

@* Confirmation dialog *@
@if (_sessionToRevoke is not null)
{
    <div class="modal-backdrop show"></div>
    <div class="modal d-block" tabindex="-1">
        <div class="modal-dialog modal-dialog-centered">
            <div class="modal-content">
                <div class="modal-header">
                    <h5 class="modal-title">Revoke Session</h5>
                    <button type="button" class="btn-close" @onclick="CancelRevoke"></button>
                </div>
                <div class="modal-body">
                    <p>
                        Are you sure you want to revoke the session on
                        <strong>@_sessionToRevoke.Device</strong> from
                        <strong>@_sessionToRevoke.Location</strong>?
                    </p>
                </div>
                <div class="modal-footer">
                    <button class="btn btn-secondary" @onclick="CancelRevoke">Cancel</button>
                    <button class="btn btn-danger" @onclick="ConfirmRevoke" disabled="@_revoking">
                        @(_revoking ? "Revoking…" : "Revoke")
                    </button>
                </div>
            </div>
        </div>
    </div>
}

@code {
    [Parameter, EditorRequired] public List<ActiveSession> Sessions { get; set; } = [];
    [Parameter] public string CurrentSessionId { get; set; } = "sess-1";
    [Parameter, EditorRequired] public EventCallback<string> OnRevoke { get; set; }

    private ActiveSession? _sessionToRevoke;
    private bool _revoking;

    private void RequestRevoke(ActiveSession session) => _sessionToRevoke = session;
    private void CancelRevoke() => _sessionToRevoke = null;

    private async Task ConfirmRevoke()
    {
        if (_sessionToRevoke is null) return;
        _revoking = true;
        await OnRevoke.InvokeAsync(_sessionToRevoke.Id);
        _revoking = false;
        _sessionToRevoke = null;
    }

    private static string FormatLastActive(DateTime dt)
    {
        var diff = DateTime.UtcNow - dt;
        if (diff.TotalMinutes < 1) return "Just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes}m ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        return $"{(int)diff.TotalDays}d ago";
    }
}

