                    <h5 style="@GetFontStyle()">Dashboard</h5>
                    <p style="@GetFontStyle()">
                        This is a preview of how your content will look with the selected settings.
                    </p>
                    <div class="d-flex gap-2 mb-2" style="@GetFontStyle()">
                        <span class="badge bg-primary">Tag 1</span>
                        <span class="badge bg-secondary">Tag 2</span>
                        <span class="badge bg-info">Tag 3</span>
                    </div>
                    <button class="btn btn-sm btn-primary" style="@GetFontStyle()">Sample Button</button>
                    <p class="mt-2 text-muted small" style="@GetFontStyle()">
