@namespace sv_cdb4f7d1ce044e3994a66919fac7e653.Components.Pages.Settings
@using sv_cdb4f7d1ce044e3994a66919fac7e653.Models
@using sv_cdb4f7d1ce044e3994a66919fac7e653.Services
@inject ISettingsService SettingsService

<h4 class="mb-4">Appearance</h4>

@if (_loading)
{
    <p class="text-muted">Loading appearance settings…</p>
}
else
{
    @if (_toastMessage is not null)
    {
        <div class="alert alert-success alert-dismissible fade show" role="alert">
            @_toastMessage
            <button type="button" class="btn-close" @onclick="() => _toastMessage = null"></button>
        </div>
    }

    <div class="row">
        <div class="col-md-6">
            <div class="card mb-4">
                <div class="card-body">
                    <h6 class="card-title mb-3">Theme</h6>
                    @foreach (var theme in new[] { "Light", "Dark", "System" })
                    {
                        <div class="form-check mb-2">
                            <input class="form-check-input" type="radio" name="theme"
                                   id="@($"theme-{theme}")"
                                   value="@theme"
                                   checked="@(_theme == theme)"
                                   @onchange="() => _theme = theme" />
                            <label class="form-check-label" for="@($"theme-{theme}")">@theme</label>
                        </div>
                    }
                </div>
            </div>

            <div class="card mb-4">
                <div class="card-body">
                    <h6 class="card-title mb-3">Font Size</h6>
                    @foreach (var size in new[] { "Small", "Medium", "Large" })
                    {
                        <div class="form-check form-check-inline">
                            <input class="form-check-input" type="radio" name="fontSize"
                                   id="@($"fs-{size}")"
                                   value="@size"
                                   checked="@(_fontSize == size)"
                                   @onchange="() => _fontSize = size" />
                            <label class="form-check-label" for="@($"fs-{size}")">@size</label>
                        </div>
                    }
                </div>
            </div>

            <div class="card mb-4">
                <div class="card-body">
                    <h6 class="card-title mb-3">Language</h6>
                    <select class="form-select" @bind="_language">
                        @foreach (var lang in _languages)
                        {
                            <option value="@lang">@lang</option>
                        }
                    </select>
                </div>
            </div>

            <div class="card mb-4">
                <div class="card-body">
                    <div class="form-check form-switch">
                        <input class="form-check-input" type="checkbox" id="compactMode"
                               checked="@_compactMode"
                               @onchange="e => _compactMode = (bool)e.Value!" />
                        <label class="form-check-label" for="compactMode">Compact Mode</label>
                    </div>
                </div>
            </div>

            <button class="btn btn-primary" @onclick="Save" disabled="@_saving">
                @(_saving ? "Saving…" : "Save")
            </button>
