.preview-dark {
    background-color: #1e1e2e;
    color: #cdd6f4;
}

.preview-dark .text-muted {
    color: #a6adc8 !important;
}

.preview-compact {
    padding: 0.5rem !important;
    line-height: 1.3;
}

.preview-compact h5 {
    margin-bottom: 0.25rem;
}

.preview-compact p {
    margin-bottom: 0.25rem;
}

