@inject ISettingsService SettingsService

<h4 class="mb-4">Profile</h4>

@if (_loading)
{
    <p class="text-muted">Loading profile…</p>
}
else
{
    @if (_toastMessage is not null)
    {
        <div class="alert alert-success alert-dismissible fade show" role="alert">
            @_toastMessage
            <button type="button" class="btn-close" @onclick="() => _toastMessage = null"></button>
        </div>
    }

    <div class="row">
        <div class="col-md-8">
            <div class="mb-3">
                <label class="form-label fw-semibold">Display Name</label>
                <input type="text" class="form-control" @bind="_displayName" />
            </div>
            <div class="mb-3">
                <label class="form-label fw-semibold">Email</label>
                <input type="email" class="form-control" @bind="_email" />
            </div>
            <div class="mb-3">
                <label class="form-label fw-semibold">Bio</label>
                <textarea class="form-control" rows="4" @bind="_bio"></textarea>
            </div>
            <div class="d-flex gap-2">
                <button class="btn btn-primary" @onclick="Save" disabled="@_saving">
                    @(_saving ? "Saving…" : "Save Changes")
                </button>
                <button class="btn btn-outline-secondary" @onclick="Discard">
                    Discard Changes
                </button>
            </div>
        </div>
        <div class="col-md-4">
            <div class="text-center">
                <div class="avatar-preview mb-2">
                    <img src="@_avatarUrl" alt="Avatar" class="rounded-circle" width="120" height="120" />
                </div>
                <div class="mb-2">
                    <label class="form-label fw-semibold">Avatar URL</label>
                    <input type="text" class="form-control form-control-sm" @bind="_avatarUrl" />
                </div>
            </div>
        </div>
    </div>
}

@code {
    private bool _loading = true;
    private bool _saving;
    private string? _toastMessage;

    private string _displayName = "";
    private string _email = "";
    private string _bio = "";
    private string _avatarUrl = "";

    // Last-saved snapshot for discard
    private UserProfile _savedProfile = null!;

    protected override async Task OnInitializedAsync()
    {
        var profile = await SettingsService.GetProfileAsync();
        ApplyProfile(profile);
        _savedProfile = profile;
        _loading = false;
    }

    private void ApplyProfile(UserProfile p)
    {
        _displayName = p.DisplayName;
        _email = p.Email;
        _bio = p.Bio;
        _avatarUrl = p.AvatarUrl;
    }

    private async Task Save()
    {
        _saving = true;
        var profile = new UserProfile(_displayName, _email, _avatarUrl, _bio);
        await SettingsService.SaveProfileAsync(profile);
        _savedProfile = profile;
        _saving = false;
        _toastMessage = "Profile saved successfully!";
    }

    private void Discard()
    {
        ApplyProfile(_savedProfile);
        _toastMessage = null;
    }
}

