@namespace sv_cdb4f7d1ce044e3994a66919fac7e653.Components.Pages.Settings
@using sv_cdb4f7d1ce044e3994a66919fac7e653.Models
@using sv_cdb4f7d1ce044e3994a66919fac7e653.Services
@inject ISettingsService SettingsService

<h4 class="mb-4">Notifications</h4>

@if (_loading)
{
    <p class="text-muted">Loading preferences…</p>
}
else
{
    @if (_toastMessage is not null)
    {
        <div class="alert alert-success alert-dismissible fade show" role="alert">
            @_toastMessage
            <button type="button" class="btn-close" @onclick="() => _toastMessage = null"></button>
        </div>
    }

    <div class="card mb-4">
        <div class="card-body">
            <h6 class="card-title mb-3">Notification Channels</h6>

            <div class="form-check form-switch mb-3">
                <input class="form-check-input" type="checkbox" id="emailNotif"
                       checked="@_emailNotifications"
                       @onchange="e => _emailNotifications = (bool)e.Value!" />
                <label class="form-check-label" for="emailNotif">Email Notifications</label>
            </div>

            <div class="form-check form-switch mb-3">
                <input class="form-check-input" type="checkbox" id="pushNotif"
                       checked="@_pushNotifications"
                       @onchange="e => _pushNotifications = (bool)e.Value!" />
                <label class="form-check-label" for="pushNotif">Push Notifications</label>
            </div>

            <div class="form-check form-switch mb-3">
                <input class="form-check-input" type="checkbox" id="weeklyDigest"
                       checked="@_weeklyDigest"
                       @onchange="e => _weeklyDigest = (bool)e.Value!" />
                <label class="form-check-label" for="weeklyDigest">Weekly Digest</label>
            </div>
        </div>
    </div>

    <div class="card mb-4">
        <div class="card-body">
            <h6 class="card-title mb-3">Muted Channels</h6>
            @foreach (var channel in _allChannels)
            {
                var isMuted = _mutedChannels.Contains(channel);
                <div class="form-check mb-2">
                    <input class="form-check-input" type="checkbox" id="@($"ch-{channel}")"
                           checked="@isMuted"
                           @onchange="e => ToggleMute(channel, (bool)e.Value!)" />
                    <label class="form-check-label" for="@($"ch-{channel}")">
                        #@channel @(isMuted ? "(muted)" : "")
                    </label>
                </div>
            }
        </div>
    </div>

    <button class="btn btn-primary" @onclick="Save" disabled="@_saving">
        @(_saving ? "Saving…" : "Save Preferences")
    </button>
}

@code {
    private bool _loading = true;
    private bool _saving;
    private string? _toastMessage;

    private bool _emailNotifications;
    private bool _pushNotifications;
    private bool _weeklyDigest;
    private HashSet<string> _mutedChannels = [];

    private static readonly string[] _allChannels =
        ["announcements", "general", "random", "off-topic", "watercooler"];

    protected override async Task OnInitializedAsync()
    {
        var prefs = await SettingsService.GetNotificationPrefsAsync();
        _emailNotifications = prefs.EmailNotifications;
        _pushNotifications = prefs.PushNotifications;
        _weeklyDigest = prefs.WeeklyDigest;
        _mutedChannels = [.. prefs.MutedChannels];
        _loading = false;
    }

    private void ToggleMute(string channel, bool muted)
    {
        if (muted)
            _mutedChannels.Add(channel);
        else
            _mutedChannels.Remove(channel);
    }

    private async Task Save()
    {
        _saving = true;
        var prefs = new NotificationPrefs(
            _emailNotifications, _pushNotifications, _weeklyDigest,
            _mutedChannels.ToList());
        await SettingsService.SaveNotificationPrefsAsync(prefs);
        _saving = false;
        _toastMessage = "Notification preferences saved!";
    }
}

