@namespace sv_cdb4f7d1ce044e3994a66919fac7e653.Components.Pages.Settings
@using sv_cdb4f7d1ce044e3994a66919fac7e653.Models
@using sv_cdb4f7d1ce044e3994a66919fac7e653.Services
@inject ISettingsService SettingsService

<h4 class="mb-4">Security</h4>

@if (_loading)
{
    <p class="text-muted">Loading security settings…</p>
}
else
{
    <ChangePasswordPanel OnPasswordChange="HandlePasswordChange" />

    <hr class="my-4" />

    <div class="card mb-4">
        <div class="card-body">
            <div class="d-flex justify-content-between align-items-center">
                <div>
                    <h6 class="mb-1">Two-Factor Authentication</h6>
                    <small class="text-muted">
                        @if (_twoFactorEnabled)
                        {
                            <span class="text-success">● Enabled</span>
                        }
                        else
                        {
                            <span class="text-danger">● Disabled</span>
                        }
                    </small>
                </div>
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox"
                           checked="@_twoFactorEnabled"
                           @onchange="e => _twoFactorEnabled = (bool)e.Value!" />
                </div>
            </div>
            @if (_lastPasswordChange.HasValue)
            {
                <small class="text-muted d-block mt-2">
                    Last password change: @_lastPasswordChange.Value.ToString("MMM dd, yyyy")
                </small>
            }
        </div>
    </div>

    <h5 class="mb-3">Active Sessions</h5>
    <ActiveSessionsTable Sessions="_sessions" OnRevoke="HandleRevoke" />
}

@code {
    private bool _loading = true;
    private bool _twoFactorEnabled;
    private DateTime? _lastPasswordChange;
    private List<ActiveSession> _sessions = [];

    protected override async Task OnInitializedAsync()
    {
        var settings = await SettingsService.GetSecuritySettingsAsync();
        _twoFactorEnabled = settings.TwoFactorEnabled;
        _lastPasswordChange = settings.LastPasswordChange;
        _sessions = settings.Sessions;
        _loading = false;
    }

    private async Task HandlePasswordChange((string Current, string New) args)
    {
        await SettingsService.ChangePasswordAsync(args.Current, args.New);
        _lastPasswordChange = DateTime.UtcNow;
    }

    private async Task HandleRevoke(string sessionId)
    {
        await SettingsService.RevokeSessionAsync(sessionId);
        _sessions = _sessions.Where(s => s.Id != sessionId).ToList();
    }
}

