@namespace sv_cdb4f7d1ce044e3994a66919fac7e653.Components.Pages.Settings
@using sv_cdb4f7d1ce044e3994a66919fac7e653.Models
@using sv_cdb4f7d1ce044e3994a66919fac7e653.Services
@inject ISettingsService SettingsService

<h4 class="mb-4">Appearance</h4>

@if (_loading)
{
    <p class="text-muted">Loading appearance settings…</p>
}
else
{
    @if (_toastMessage is not null)
    {
        <div class="alert alert-success alert-dismissible fade show" role="alert">
            @_toastMessage
            <button type="button" class="btn-close" @onclick="() => _toastMessage = null"></button>
        </div>
    }

    <div class="row">
        <div class="col-md-6">
            <div class="card mb-4">
                <div class="card-body">
                    <h6 class="card-title mb-3">Theme</h6>
                    @foreach (var theme in new[] { "Light", "Dark", "System" })
                    {
                        <div class="form-check mb-2">
                            <input class="form-check-input" type="radio" name="theme"
                                   id="@($"theme-{theme}")"
                                   value="@theme"
                                   checked="@(_theme == theme)"
                                   @onchange="() => _theme = theme" />
                            <label class="form-check-label" for="@($"theme-{theme}")">@theme</label>
                        </div>
                    }
                </div>
            </div>

            <div class="card mb-4">
                <div class="card-body">
                    <h6 class="card-title mb-3">Font Size</h6>
                    @foreach (var size in new[] { "Small", "Medium", "Large" })
                    {
                        <div class="form-check form-check-inline">
                            <input class="form-check-input" type="radio" name="fontSize"
                                   id="@($"fs-{size}")"
                                   value="@size"
                                   checked="@(_fontSize == size)"
                                   @onchange="() => _fontSize = size" />
                            <label class="form-check-label" for="@($"fs-{size}")">@size</label>
                        </div>
                    }
                </div>
            </div>

            <div class="card mb-4">
                <div class="card-body">
                    <h6 class="card-title mb-3">Language</h6>
                    <select class="form-select" @bind="_language">
                        @foreach (var lang in _languages)
                        {
                            <option value="@lang">@lang</option>
                        }
                    </select>
                </div>
            </div>

            <div class="card mb-4">
                <div class="card-body">
                    <div class="form-check form-switch">
                        <input class="form-check-input" type="checkbox" id="compactMode"
                               checked="@_compactMode"
                               @onchange="e => _compactMode = (bool)e.Value!" />
                        <label class="form-check-label" for="compactMode">Compact Mode</label>
                    </div>
                </div>
            </div>

            <button class="btn btn-primary" @onclick="Save" disabled="@_saving">
                @(_saving ? "Saving…" : "Save")
            </button>
        </div>

        <div class="col-md-6">
            <div class="card">
                <div class="card-header">
                    <h6 class="mb-0">Live Preview</h6>
                </div>
                <div class="card-body preview-area @GetPreviewClasses()">
                    <h5 style="@GetFontStyle()">Dashboard</h5>
                    <p style="@GetFontStyle()">
                        This is a preview of how your content will look with the selected settings.
                    </p>
                    <div class="d-flex gap-2 mb-2" style="@GetFontStyle()">
                        <span class="badge bg-primary">Tag 1</span>
                        <span class="badge bg-secondary">Tag 2</span>
                        <span class="badge bg-info">Tag 3</span>
                    </div>
                    <button class="btn btn-sm btn-primary" style="@GetFontStyle()">Sample Button</button>
                    <p class="mt-2 text-muted small" style="@GetFontStyle()">
                        Language: @_language · Compact: @(_compactMode ? "On" : "Off")
                    </p>
                </div>
            </div>
        </div>
    </div>
}

@code {
    private bool _loading = true;
    private bool _saving;
    private string? _toastMessage;

    private string _theme = "Light";
    private string _fontSize = "Medium";
    private string _language = "English";
    private bool _compactMode;

    private static readonly string[] _languages =
        ["English", "Spanish", "French", "German", "Japanese", "Chinese", "Portuguese"];

    protected override async Task OnInitializedAsync()
    {
        var settings = await SettingsService.GetAppearanceAsync();
        _theme = settings.Theme;
        _fontSize = settings.FontSize;
        _language = settings.Language;
        _compactMode = settings.CompactMode;
        _loading = false;
    }

    private string GetPreviewClasses()
    {
        var classes = new List<string>();
        if (_theme == "Dark") classes.Add("preview-dark");
        if (_compactMode) classes.Add("preview-compact");
        return string.Join(" ", classes);
    }

    private string GetFontStyle() => _fontSize switch
    {
        "Small" => "font-size: 0.85rem;",
        "Large" => "font-size: 1.15rem;",
        _ => "font-size: 1rem;"
    };

    private async Task Save()
    {
        _saving = true;
        var settings = new AppearanceSettings(_theme, _fontSize, _language, _compactMode);
        await SettingsService.SaveAppearanceAsync(settings);
        _saving = false;
        _toastMessage = "Appearance settings saved!";
    }
}

.preview-area {
    transition: all 0.2s ease;
    min-height: 180px;
    border-radius: 0 0 0.375rem 0.375rem;
}

.preview-dark {
    background-color: #1e1e2e;
    color: #cdd6f4;
}

.preview-dark .text-muted {
    color: #a6adc8 !important;
}

.preview-compact {
    padding: 0.5rem !important;
    line-height: 1.3;
}

.preview-compact h5 {
    margin-bottom: 0.25rem;
}

.preview-compact p {
    margin-bottom: 0.25rem;
}

